from jinja2 import Environment
from jinja2.ext import i18n
from jinja2.exceptions import TemplateAssertionError

# --- old-style, with a translations object supporting dgettext/dngettext ---
class FakeTranslations:
    def gettext(self, message):
        return 'G:' + message
    def ngettext(self, s, p, n):
        return ('NG1:' + s) if n == 1 else ('NGN:' + p)
    def dgettext(self, domain, message):
        return f'D[{domain}]:' + message
    def dngettext(self, domain, s, p, n):
        return (f'DN1[{domain}]:' + s) if n == 1 else (f'DNN[{domain}]:' + p)

env = Environment(extensions=[i18n])
env.install_gettext_translations(FakeTranslations(), newstyle=False)

t = env.from_string('{% trans domain=\"mydomain\" %}Hello{% endtrans %}')
print(repr(t.render()))

t2 = env.from_string('{% trans domain=\"mydomain\", count=3 %}{{ count }} item{% pluralize %}{{ count }} items{% endtrans %}')
print(repr(t2.render()))

# newstyle
